"""
Property-based tests for peyesim using hypothesis.

These tests verify that functions maintain expected properties across
a wide range of inputs.
"""

import numpy as np
import pytest
from hypothesis import given, strategies as st, assume, settings
from hypothesis.extra.numpy import arrays
from numpy.testing import assert_allclose

from peyesim import (
    fixation_group,
    center_fixations,
    normalize_fixations,
    scale_fixations,
    rotate_fixations,
    similarity,
    compute_saccades,
    fixation_overlap
)


# Custom strategies for generating valid fixation data
@st.composite
def fixation_arrays(draw, min_length=1, max_length=100):
    """Generate valid fixation coordinate arrays."""
    n = draw(st.integers(min_value=min_length, max_value=max_length))

    x = draw(arrays(np.float64, n, 
                    elements=st.floats(min_value=0, max_value=1000, 
                                     allow_nan=False, allow_infinity=False)))
    y = draw(arrays(np.float64, n,
                    elements=st.floats(min_value=0, max_value=1000,
                                     allow_nan=False, allow_infinity=False)))
    onset = draw(arrays(np.float64, n,
                       elements=st.floats(min_value=0, max_value=10000,
                                        allow_nan=False, allow_infinity=False)))
    onset = np.sort(onset)  # Ensure onset times are sorted

    # Generate durations
    if n == 1:
        duration = np.array([100.0])
    else:
        # Ensure durations don't overlap
        max_durations = np.append(np.diff(onset), 100)
        duration = draw(arrays(np.float64, n,
                             elements=st.floats(min_value=10, max_value=100,
                                              allow_nan=False, allow_infinity=False)))
        duration = np.minimum(duration, max_durations * 0.9)

    return x, y, onset, duration


@st.composite  
def fixation_groups(draw, min_length=1, max_length=100):
    """Generate valid FixationGroup objects."""
    x, y, onset, duration = draw(fixation_arrays(min_length, max_length))
    return fixation_group(x, y, onset, duration)


class TestTransformProperties:
    """Test properties of transformation functions."""

    @given(fg=fixation_groups(min_length=2))
    @settings(max_examples=50)
    def test_center_fixations_mean_zero(self, fg):
        """Centered fixations should have mean ~0."""
        centered = center_fixations(fg)

        # Mean should be approximately zero
        assert_allclose(np.mean(centered.x), 0, atol=1e-10)
        assert_allclose(np.mean(centered.y), 0, atol=1e-10)

        # Other properties should be preserved
        assert len(centered) == len(fg)
        assert_allclose(centered.onset, fg.onset)
        assert_allclose(centered.duration, fg.duration)

    @given(fg=fixation_groups(min_length=3))
    @settings(max_examples=50)
    def test_normalize_fixations_unit_variance(self, fg):
        """Normalized fixations should have unit variance."""
        # Skip if all values are the same
        if np.var(fg.x) < 1e-10 or np.var(fg.y) < 1e-10:
            return

        normalized = normalize_fixations(fg)

        # Variance should be approximately 1
        assert_allclose(np.var(normalized.x), 1.0, rtol=0.01)
        assert_allclose(np.var(normalized.y), 1.0, rtol=0.01)

    @given(fg=fixation_groups(), 
           scale_x=st.floats(min_value=0.1, max_value=10),
           scale_y=st.floats(min_value=0.1, max_value=10))
    @settings(max_examples=50)
    def test_scale_fixations_proportional(self, fg, scale_x, scale_y):
        """Scaling should change coordinates proportionally."""
        scaled = scale_fixations(fg, scale=(scale_x, scale_y))

        # Coordinates should be scaled
        assert_allclose(scaled.x, fg.x * scale_x, rtol=1e-10)
        assert_allclose(scaled.y, fg.y * scale_y, rtol=1e-10)

        # Temporal properties unchanged
        assert_allclose(scaled.onset, fg.onset)
        assert_allclose(scaled.duration, fg.duration)

    @given(fg=fixation_groups(min_length=2),
           angle=st.floats(min_value=0, max_value=2*np.pi))
    @settings(max_examples=30)
    def test_rotate_fixations_preserves_distances(self, fg, angle):
        """Rotation should preserve distances between points."""
        rotated = rotate_fixations(fg, angle=angle)

        # Compute pairwise distances before and after
        for i in range(len(fg)):
            for j in range(i+1, len(fg)):
                dist_before = np.sqrt((fg.x[i] - fg.x[j])**2 + 
                                    (fg.y[i] - fg.y[j])**2)
                dist_after = np.sqrt((rotated.x[i] - rotated.x[j])**2 + 
                                   (rotated.y[i] - rotated.y[j])**2)
                assert_allclose(dist_after, dist_before, rtol=1e-10)


class TestSimilarityProperties:
    """Test properties of similarity functions."""

    @given(fg=fixation_groups(min_length=3))
    @settings(max_examples=50)
    def test_similarity_self_is_one(self, fg):
        """Similarity of a fixation group with itself should be 1."""
        for method in ['pearson', 'spearman']:
            sim = similarity(fg, fg, method=method)
            if not np.isnan(sim):  # Skip if not enough variation
                assert_allclose(sim, 1.0, rtol=1e-10)

    @given(fg1=fixation_groups(min_length=3),
           fg2=fixation_groups(min_length=3))
    @settings(max_examples=30)
    def test_similarity_symmetry(self, fg1, fg2):
        """Similarity should be symmetric."""
