# Custom strategies for generating valid fixation data
@st.composite
def fixation_arrays(draw, min_length=1, max_length=100):
    """Generate valid fixation coordinate arrays."""
    n = draw(st.integers(min_value=min_length, max_value=max_length))

    x = draw(arrays(np.float64, n, 
                    elements=st.floats(min_value=0, max_value=1000, 
                                     allow_nan=False, allow_infinity=False)))
    y = draw(arrays(np.float64, n,
                    elements=st.floats(min_value=0, max_value=1000,
                                     allow_nan=False, allow_infinity=False)))
    onset = draw(arrays(np.float64, n,
                       elements=st.floats(min_value=0, max_value=10000,
                                        allow_nan=False, allow_infinity=False)))
    onset = np.sort(onset)  # Ensure onset times are sorted

    # Generate durations
    if n == 1:
        duration = np.array([100.0])
    else:
        # Ensure durations don't overlap
        max_durations = np.append(np.diff(onset), 100)
        duration = draw(arrays(np.float64, n,
                             elements=st.floats(min_value=10, max_value=100,
                                              allow_nan=False, allow_infinity=False)))
        duration = np.minimum(duration, max_durations * 0.9)

    return x, y, onset, duration


@st.composite  
def fixation_groups(draw, min_length=1, max_length=100):
    """Generate valid FixationGroup objects."""
    x, y, onset, duration = draw(fixation_arrays(min_length, max_length))
    return fixation_group(x, y, onset, duration)


